const fs = require('fs');
const path = require('path');

const body = $input.item.json.body || $input.item.json;
const title = (body.title || 'unnamed-app').toString();
const prompt = (body.prompt || '').toString();
const stack = (body.stack || 'React + Vite').toString();

const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)/g, '')
  .substring(0, 40);

const appDir = path.join('C:\\Users\\Student\\AI-Projekt\\workspace', slug);

fs.mkdirSync(appDir, { recursive: true });
fs.writeFileSync(path.join(appDir, 'PROMPT.md'), prompt, 'utf8');

return [{ json: { title, slug, appDir, stack } }];

const { spawnSync } = require('child_process');

const appDir = $input.item.json.appDir;
const promptFile = appDir + '\\PROMPT.md';

const result = spawnSync(
  'powershell.exe',
  ['-Command', `$p = Get-Content '${promptFile}' -Raw; cd '${appDir}'; $p | claude --dangerously-skip-permissions`],
  { timeout: 600000, encoding: 'utf8' }
);

const output = (result.stdout || '').substring(0, 1000);
const hasError = result.status !== 0;

return [{ json: { ...$input.item.json, claudeOutput: output, claudeFailed: hasError } }];

const { execSync } = require('child_process');

const appDir = $input.item.json.appDir;
const slug = $input.item.json.slug;
const opts = { cwd: appDir, encoding: 'utf8', stdio: 'pipe' };

let gitStatus = 'unknown';

try {
  try { execSync('git init', opts); } catch {}
  execSync('git add .', opts);
  execSync(`git commit -m "${slug}: initial build by FreeBots"`, opts);
  gitStatus = 'committed';

  try {
    execSync('git push', opts);
    gitStatus = 'pushed';
  } catch {
    gitStatus = 'committed-no-remote';
  }
} catch(e) {
  gitStatus = 'error: ' + e.message.substring(0, 100);
}

return [{ json: { ...$input.item.json, gitStatus } }];

